package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.ast.NodeList;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.stream.Stream;

public class Main {
    public static void main(String[] args) throws IOException {
        String sourceDir = "/workspace/license-maven-plugin/license-maven-plugin/src/main/java";

        try (Stream<Path> paths = Files.walk(Paths.get(sourceDir))) {
            paths.filter(Files::isRegularFile)
                 .filter(p -> p.toString().endsWith(".java"))
                 .forEach(Main::transformFile);
        }
    }

    private static void transformFile(Path path) {
        try {
            CompilationUnit cu = StaticJavaParser.parse(path);

            cu.findAll(MethodCallExpr.class).forEach(methodCall -> {
                if (methodCall.getNameAsString().equals("buildDependencyGraph")) {
                    NodeList<Expression> args = methodCall.getArguments();
                    if (args.size() >= 2) {
                        Expression firstArg = args.get(0);
                        if (firstArg instanceof NameExpr) {
                            NameExpr nameExpr = (NameExpr) firstArg;
                            if (nameExpr.getNameAsString().equals("project")) {
                                args.set(0, new NameExpr("getBuildingRequest()"));
                            }
                        }
                    }
                }
            });

            Files.writeString(path, cu.toString());
            System.out.println("Transformed: " + path);
        } catch (IOException e) {
            System.err.println("Error processing " + path + ": " + e.getMessage());
        }
    }
}

